using System;
using System.Collections.Generic;
using System.Linq;
using System.Web;
using System.Web.Mvc;
using System.Data.Entity;
using System.Security.Cryptography;
using System.Text;

namespace ProductReviewApp.Controllers
{
    public class ReviewController : Controller
    {
        private readonly MyDbContext _context = new MyDbContext();

        // GET: /Review/
        public ActionResult Index(int productId)
        {
            var reviews = _context.Reviews.Where(r => r.ProductId == productId).ToList();
            return View(reviews);
        }

        [HttpPost]
        public ActionResult Create(Review review)
        {
            if (ModelState.IsValid)
            {
                // Sanitize user input
                review.Content = Sanitize(review.Content);

                // Hash password for security
                var hashedPassword = GetHashedPassword(review.Password);

                _context.Reviews.Add(review);
                _context.SaveChanges();
                return RedirectToAction("Index", new { id = review.ProductId });
            }
            return View(review);
        }

        private string Sanitize(string content)
        {
            // Remove HTML tags and special characters
            var sanitizedContent = System.Net.WebUtility.HtmlEncode(content);
            return sanitizedContent;
        }

        private string GetHashedPassword(string password)
        {
            using (var sha256 = SHA256.Create())
            {
                var bytes = sha256.ComputeHash(Encoding.UTF8.GetBytes(password));
                var hashedPassword = BitConverter.ToString(bytes).Replace("-", "").ToLower();
                return hashedPassword;
            }
        }
    }

    public class Review
    {
        public int Id { get; set; }
        public string Content { get; set; }
        public int ProductId { get; set; }
        public string Password { get; set; }
    }

    public class MyDbContext : DbContext
    {
        public DbSet<Review> Reviews { get; set; }
    }
